import 'reflect-metadata';
import { NestFactory } from '@nestjs/core';
import { Logger } from '@nestjs/common';
import { MicroserviceOptions, Transport } from '@nestjs/microservices';
import { AppModule } from './app.module';

async function bootstrap(): Promise<void> {
  const logger = new Logger('Worker');

  // Standalone application — no HTTP listener.
  const app = await NestFactory.createApplicationContext(AppModule, {
    bufferLogs: false,
  });

  const natsUrl = process.env.NATS_URL;
  if (!natsUrl) {
    logger.error('NATS_URL is not set — cannot start worker');
    process.exit(1);
  }

  // Attach a hybrid NATS microservice so @EventPattern handlers fire.
  const micro = app.get(AppModule); // keep reference for lifecycle; app.close() handles it
  const nestApp = app as unknown as {
    connectMicroservice: (opts: MicroserviceOptions) => any;
    startAllMicroservices: () => Promise<void>;
  };

  // createApplicationContext does NOT expose connectMicroservice; we need
  // the full INestApplication for hybrid mode. Recreate as hybrid.
  await app.close();

  const hybrid = await NestFactory.create(AppModule, { bufferLogs: false });
  hybrid.connectMicroservice<MicroserviceOptions>({
    transport: Transport.NATS,
    options: {
      servers: [natsUrl],
      queue: 'worker',
    },
  });

  // Lifecycle: drain in-flight messages on SIGTERM.
  const shutdown = async (signal: string): Promise<void> => {
    logger.log(`received ${signal} — draining and closing`);
    try {
      await hybrid.close();
      logger.log('shutdown complete');
      process.exit(0);
    } catch (err) {
      logger.error(`error during shutdown: ${(err as Error).message}`);
      process.exit(1);
    }
  };
  process.on('SIGTERM', () => void shutdown('SIGTERM'));
  process.on('SIGINT', () => void shutdown('SIGINT'));

  await hybrid.startAllMicroservices();
  logger.log(`worker bootstrapped — connected to NATS at ${redactUrl(natsUrl)}`);
  logger.log('subscribed to notes.created, notes.deleted');

  // Keep process alive (hybrid app has no HTTP listener we need to .listen() on).
  // startAllMicroservices keeps the event loop busy via NATS client sockets.
}

function redactUrl(url: string): string {
  try {
    const u = new URL(url);
    if (u.password) u.password = '***';
    return u.toString();
  } catch {
    return '<unparseable>';
  }
}

bootstrap().catch((err) => {
  // eslint-disable-next-line no-console
  console.error('bootstrap failed', err);
  process.exit(1);
});

