import { Controller, Inject, Logger } from '@nestjs/common';
import { EventPattern, Payload } from '@nestjs/microservices';
import { Pool } from 'pg';
import { PG_POOL } from '../db/db.module';

interface NoteEventPayload {
  id?: string | number;
  noteId?: string | number;
  [k: string]: unknown;
}

@Controller()
export class NotesConsumer {
  private readonly logger = new Logger(NotesConsumer.name);

  constructor(@Inject(PG_POOL) private readonly pool: Pool) {}

  @EventPattern('notes.created')
  async onCreated(@Payload() data: NoteEventPayload): Promise<void> {
    await this.record('notes.created', data);
  }

  @EventPattern('notes.deleted')
  async onDeleted(@Payload() data: NoteEventPayload): Promise<void> {
    await this.record('notes.deleted', data);
  }

  private async record(event: string, data: NoteEventPayload): Promise<void> {
    const noteId = this.extractNoteId(data);
    this.logger.log(`event=${event} noteId=${noteId ?? '<none>'}`);
    try {
      await this.pool.query(
        'INSERT INTO note_events (event, note_id) VALUES ($1, $2)',
        [event, noteId],
      );
    } catch (err) {
      this.logger.error(
        `failed to persist ${event} audit row: ${(err as Error).message}`,
      );
      throw err;
    }
  }

  private extractNoteId(data: NoteEventPayload): string | null {
    const raw = data?.noteId ?? data?.id;
    if (raw === undefined || raw === null) return null;
    return String(raw);
  }
}

import { Pool } from 'pg';

async function main(): Promise<void> {
  const connectionString = process.env.POSTGRES_URL;
  if (!connectionString) {
    console.error('POSTGRES_URL is not set');
    process.exit(1);
  }
  const pool = new Pool({ connectionString, max: 2 });
  try {
    console.log('[migrate] ensuring note_events table');
    await pool.query(`
      CREATE TABLE IF NOT EXISTS note_events (
        id          BIGSERIAL PRIMARY KEY,
        event       TEXT NOT NULL,
        note_id     TEXT,
        created_at  TIMESTAMPTZ NOT NULL DEFAULT now()
      )
    `);
    await pool.query(`
      CREATE INDEX IF NOT EXISTS note_events_created_at_idx
        ON note_events (created_at DESC)
    `);
    console.log('[migrate] note_events ready');
  } finally {
    await pool.end();
  }
}

main().catch((err) => {
  console.error('[migrate] failed:', err);
  process.exit(1);
});

