import 'reflect-metadata';
import { Logger } from '@nestjs/common';
import { NestFactory } from '@nestjs/core';
import { MicroserviceOptions, Transport } from '@nestjs/microservices';
import { AppModule } from './app.module';

async function bootstrap(): Promise<void> {
  const logger = new Logger('Worker');

  // nats.js servers[] wants host:port (not a nats:// URL with creds —
  // it rewrites entries as http://[…] internally, which breaks the URL
  // parser for any embedded userinfo). Pass creds via user/pass options.
  const host = process.env.broker_hostname;
  const port = process.env.broker_port;
  const user = process.env.broker_user;
  const pass = process.env.broker_password;
  if (!host || !port || !user || !pass) {
    logger.error('broker_* env vars are not fully set — cannot start worker');
    process.exit(1);
  }

  // Pure microservice — no HTTP driver. NestFactory.create() would
  // require @nestjs/platform-express; this path does not, matching the
  // worker role (ServesHTTP=false, no ports block in zerops.yaml).
  const app = await NestFactory.createMicroservice<MicroserviceOptions>(
    AppModule,
    {
      transport: Transport.NATS,
      options: {
        servers: [`${host}:${port}`],
        user,
        pass,
        queue: 'worker',
      },
      bufferLogs: false,
    },
  );

  // SIGTERM drains in-flight NATS messages before exit. Zerops sends
  // SIGTERM before rescheduling / rolling the container.
  const shutdown = async (signal: string): Promise<void> => {
    logger.log(`received ${signal} — draining and closing`);
    try {
      await app.close();
      logger.log('shutdown complete');
      process.exit(0);
    } catch (err) {
      logger.error(`error during shutdown: ${(err as Error).message}`);
      process.exit(1);
    }
  };
  process.on('SIGTERM', () => void shutdown('SIGTERM'));
  process.on('SIGINT', () => void shutdown('SIGINT'));

  await app.listen();
  logger.log(`connected to NATS at ${host}:${port} (user=${user})`);
  logger.log('subscribed to notes.created, notes.deleted (queue=worker)');
}

bootstrap().catch((err) => {
  // eslint-disable-next-line no-console
  console.error('bootstrap failed', err);
  process.exit(1);
});

